import{_ as r,o as a,c as d,a2 as e}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"入金未到账怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/deposit-not-received.md","filePath":"zh-CN/troubleshooting/deposit-not-received.md"}'),o={name:"troubleshooting/deposit-not-received.md"};function i(l,t,n,s,h,p){return a(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="入金未到账怎么办" tabindex="-1">入金未到账怎么办 <a class="header-anchor" href="#入金未到账怎么办" aria-label="Permalink to &quot;入金未到账怎么办&quot;">​</a></h1><p>转账已在银行端完成，但长桥账户余额未更新时，请按以下步骤排查。</p><h2 id="第一步-确认是否在预期到账时间内" tabindex="-1">第一步：确认是否在预期到账时间内 <a class="header-anchor" href="#第一步-确认是否在预期到账时间内" aria-label="Permalink to &quot;第一步：确认是否在预期到账时间内&quot;">​</a></h2><p>不同入金方式的处理时间不同，先对照下表确认是否已超时：</p><table tabindex="0"><thead><tr><th>入金方式</th><th>预期到账时间</th></tr></thead><tbody><tr><td>eDDA 快捷入金（港股交易日）</td><td>5 分钟内</td></tr><tr><td>eDDA（非交易日或节假日）</td><td>下一个港股交易日 09:40 前</td></tr><tr><td>FPS 转数快（港股交易日）</td><td>2 小时内</td></tr><tr><td>FPS 转数快（其他时段）</td><td>下一个港股交易日 09:40 前</td></tr><tr><td>网银同行转账（HK）</td><td>约 2 小时</td></tr><tr><td>网银跨行转账（HK）</td><td>1–3 个工作日</td></tr><tr><td>海外电汇（USD）</td><td>2–5 个交易日</td></tr><tr><td>DDA（新加坡）</td><td>实时到账</td></tr><tr><td>PayNow（新加坡）</td><td>实时到账</td></tr></tbody></table><p><strong>如果仍在预期时间范围内</strong>：继续等待，香港节假日期间顺延。</p><p><strong>如果已超出预期时间</strong>：继续下一步。</p><h2 id="第二步-确认银行端转账已成功" tabindex="-1">第二步：确认银行端转账已成功 <a class="header-anchor" href="#第二步-确认银行端转账已成功" aria-label="Permalink to &quot;第二步：确认银行端转账已成功&quot;">​</a></h2><p>打开银行 App 或网银，查看该笔转账的状态：</p><ul><li>如果显示「交易失败」或「退款」：资金已退回银行账户，需重新发起入金</li><li>如果显示「处理中」或「已扣款但未到账」：继续下一步</li><li>如果显示「成功」但长桥未到账：继续下一步</li></ul><h2 id="第三步-检查入金申请信息是否有误" tabindex="-1">第三步：检查入金申请信息是否有误 <a class="header-anchor" href="#第三步-检查入金申请信息是否有误" aria-label="Permalink to &quot;第三步：检查入金申请信息是否有误&quot;">​</a></h2><p>进入长桥 App → 资产 → 存入资金 → 入金记录，找到该笔申请：</p><ul><li>如果状态为**「审核中」**：等待审批，通常 2 小时内完成（节假日顺延）</li><li>如果状态为**「已驳回」**：点击记录查看驳回原因，按提示修改后重新提交</li><li>如果<strong>找不到该记录</strong>：可能未完成入金申请，仅完成了银行转账但未在 App 内提交凭证（网银入金需上传汇款截图）</li></ul><h3 id="常见驳回原因" tabindex="-1">常见驳回原因 <a class="header-anchor" href="#常见驳回原因" aria-label="Permalink to &quot;常见驳回原因&quot;">​</a></h3><table tabindex="0"><thead><tr><th>驳回原因</th><th>处理方式</th></tr></thead><tbody><tr><td>账户名不一致</td><td>确认银行账户名与长桥账户名完全一致，使用本人同名账户重新转账</td></tr><tr><td>汇款备注缺失</td><td>网银/电汇须填写证券账户号+姓名；重新转账并填写备注</td></tr><tr><td>转账金额与凭证不符</td><td>重新上传正确的汇款凭证</td></tr><tr><td>非 FATF 成员地区</td><td>境外账户须来自 FATF 成员国家/地区，不接受中国大陆内地银行卡</td></tr></tbody></table><h2 id="第四步-确认收款账号填写正确" tabindex="-1">第四步：确认收款账号填写正确 <a class="header-anchor" href="#第四步-确认收款账号填写正确" aria-label="Permalink to &quot;第四步：确认收款账号填写正确&quot;">​</a></h2><p>如使用网银或电汇，确认收款账号与以下信息一致：</p><ul><li><strong>港元入金</strong>：工商银行亚洲，账号 861520160012，SWIFT：UBHKHKHHXXX</li><li><strong>美元入金</strong>：创兴银行，账号 256150608546，SWIFT：LCHBHKHH</li><li><strong>海外电汇（USD）</strong>：工商银行亚洲，账号 861530198867</li></ul><p>如收款账号有误，资金可能进入错误账户，需联系银行追回。</p><h2 id="仍未解决" tabindex="-1">仍未解决 <a class="header-anchor" href="#仍未解决" aria-label="Permalink to &quot;仍未解决&quot;">​</a></h2><p>准备以下信息联系客服：</p><ul><li>转账银行流水截图（显示交易时间、金额、收款账号）</li><li>入金方式（FPS / 网银 / eDDA 等）</li><li>长桥入金记录截图（如有）</li></ul><p><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服</p><p><strong>客服热线</strong>：4000712688</p>',24)])])}const b=r(o,[["render",i]]);export{u as __pageData,b as default};
